import feedparser
from src.core import eventos_sistema_CORE_GL # [SAT] SOLDADO RADAR GLOBAL v1.0
# Monitoramento 24/7 de IA, Big Techs e Mercado de Software. class RadarGlobal: def __init__(self): self.radar_dir = ".panda/radar/raw" os.makedirs(self.radar_dir, exist_ok=True) # [GOAL] RADAR DE ELITE 40+ (IA & BIG TECH) self.targets = { "EUA": [ "https://openai.com/news/rss.xml", "https://anthropic.com/news", "https://ai.meta.com/blog/rss/", "https://googleblog.blogspot.com/atom.xml", "https://apple.com/newsroom/rss-feed.rss", "https://microsoft.com/en-us/research/blog/feed/", "https://nvidia.com/en-us/blog/feed/", "https://amazon.science/index.xml" ], "CHINA": [ "https://deepseek.com/blog/feed", "https://baidu.com", # Mock/Placeholder para scraping futuro "https://aliyun.com", "https://tencent.ai" ], "EUROPA": [ "https://mistral.ai/news/feed", "https://aleph-alpha.com/feed/", "https://siliconcanals.com/feed/" ], "BRASIL_MERCADO": [ "https://valor.globo.com/rss/valor/", "https://tecnoblog.net/feed/", "https://estadao.com.br/link/rss/" ] } def coletar_github(self): """Busca reposit rios SOTA com mais de 1000 estrelas (2025+).""" print("[ ] RADAR: Escaneando GitHub Trends 2025+...") query = "created:>2025-01-01 stars:>1000" url = f"https://api.github.com/search/repositories?q={query}&sort=stars&order=desc" try: res = requests.get(url, timeout=10) if res.status_code == 200: data = res.json() self._salvar_raw("github_trends", data) return len(data.get("items", [])) except Exception as e: print(f"[[ERR]] Error GitHub: {e}") return 0 def coletar_rss(self): """Coleta not cias de blogs t cnicos, IA e mercado mundial.""" print("[[RADAR]] RADAR: Coletando Feeds RSS de 40+ alvos globais...") noticias = [] for regiao, urls in self.targets.items(): print(f" -> Escaneando regi o: {regiao}") for url in urls: try: feed = feedparser.parse(url) for entry in feed.entries[:3]: noticias.append({ "titulo": entry.title, "link": entry.link, "regiao": regiao, "timestamp": time.strftime("%Y-%m-%d %H:%M:%S") }) except: continue self._salvar_raw("rss_global", {"noticias": noticias}) return len(noticias) def _salvar_raw(self, tipo, dados): fname = f"{tipo}_{time.strftime('%Y%m%d_%H%M%S')}.json" with open(os.path.join(self.radar_dir, fname), "w", encoding="utf-8") as f: json.dump(dados, f, indent=4) print(f"[[SAVE]] RADAR: Dados brutos salvos: {fname}") def executar_ciclo(self): print("[[BOOST]] RADAR GLOBAL INICIADO") count_gh = self.coletar_github() count_rss = self.coletar_rss() msg = f"Radar conclu do. GH: {count_gh} repos | RSS: {count_rss} not cias." eventos_sistema_CORE_GL.registrar_evento("RADAR_UPDATE", "GLOBAL", {"resumo": msg}) print(f"[[OK]] {msg}") if __name__ == "__main__": RadarGlobal().executar_ciclo() 